import{_ as a,o,c as r,a4 as t}from"./chunks/framework.Cj8rJHTG.js";const f=JSON.parse('{"title":"Interface: ThemeColors · core","description":"","frontmatter":{"title":"Interface: ThemeColors · core"},"headers":[],"relativePath":"api/core/interfaces/ThemeColors.md","filePath":"api/core/interfaces/ThemeColors.md"}'),s={name:"api/core/interfaces/ThemeColors.md"};function n(c,e,l,d,i,h){return o(),r("div",null,[...e[0]||(e[0]=[t('<p><a href="./../">@jsvision/core</a> / ThemeColors</p><h1 id="interface-themecolors" tabindex="-1">Interface: ThemeColors <a class="header-anchor" href="#interface-themecolors" aria-label="Permalink to &quot;Interface: ThemeColors&quot;">​</a></h1><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/61db895436cf02931389daaaf2bf33e111871d25/packages/core/src/engine/color/aliases.ts#L25" target="_blank" rel="noreferrer">color/aliases.ts:25</a></p><p>The 18 semantic color aliases a generated theme is built from.</p><p>Each token is a <a href="./../type-aliases/Color.html">Color</a> (hex, a named ANSI-16 color, or <code>&#39;default&#39;</code>) and carries a fixed meaning — the groups are text, surface, accent, accelerator, line, and status. <code>rolesFromAliases</code> maps every one of the 68 UI roles onto its nearest token by purpose, so changing (say) <code>accent</code> re-colors every focus/selection surface at once.</p><p>This is a type — it has no runtime footprint and is exempt from the <code>@example</code> doc rule; build a value with <code>createTheme</code> (or an object literal) instead.</p><h2 id="properties" tabindex="-1">Properties <a class="header-anchor" href="#properties" aria-label="Permalink to &quot;Properties&quot;">​</a></h2><h3 id="accelerator" tabindex="-1">accelerator <a class="header-anchor" href="#accelerator" aria-label="Permalink to &quot;accelerator&quot;">​</a></h3><blockquote><p><code>readonly</code> <strong>accelerator</strong>: <a href="./../type-aliases/Color.html"><code>Color</code></a></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/61db895436cf02931389daaaf2bf33e111871d25/packages/core/src/engine/color/aliases.ts#L54" target="_blank" rel="noreferrer">color/aliases.ts:54</a></p><p>The highlighted hotkey letter of an in-dialog control — a focused button, a tab, a label/cluster shortcut.</p><hr><h3 id="accent" tabindex="-1">accent <a class="header-anchor" href="#accent" aria-label="Permalink to &quot;accent&quot;">​</a></h3><blockquote><p><code>readonly</code> <strong>accent</strong>: <a href="./../type-aliases/Color.html"><code>Color</code></a></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/61db895436cf02931389daaaf2bf33e111871d25/packages/core/src/engine/color/aliases.ts#L48" target="_blank" rel="noreferrer">color/aliases.ts:48</a></p><p>The brand/focus color — focused rows, the default button, selected menu/tab fills.</p><hr><h3 id="accentmuted" tabindex="-1">accentMuted <a class="header-anchor" href="#accentmuted" aria-label="Permalink to &quot;accentMuted&quot;">​</a></h3><blockquote><p><code>readonly</code> <strong>accentMuted</strong>: <a href="./../type-aliases/Color.html"><code>Color</code></a></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/61db895436cf02931389daaaf2bf33e111871d25/packages/core/src/engine/color/aliases.ts#L50" target="_blank" rel="noreferrer">color/aliases.ts:50</a></p><p>A dimmer/pressed step of <a href="#accent">accent</a> — a focused button face, an inactive tab.</p><hr><h3 id="background" tabindex="-1">background <a class="header-anchor" href="#background" aria-label="Permalink to &quot;background&quot;">​</a></h3><blockquote><p><code>readonly</code> <strong>background</strong>: <a href="./../type-aliases/Color.html"><code>Color</code></a></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/61db895436cf02931389daaaf2bf33e111871d25/packages/core/src/engine/color/aliases.ts#L38" target="_blank" rel="noreferrer">color/aliases.ts:38</a></p><p>The base backdrop — the desktop field behind all windows.</p><hr><h3 id="backgroundraised" tabindex="-1">backgroundRaised <a class="header-anchor" href="#backgroundraised" aria-label="Permalink to &quot;backgroundRaised&quot;">​</a></h3><blockquote><p><code>readonly</code> <strong>backgroundRaised</strong>: <a href="./../type-aliases/Color.html"><code>Color</code></a></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/61db895436cf02931389daaaf2bf33e111871d25/packages/core/src/engine/color/aliases.ts#L40" target="_blank" rel="noreferrer">color/aliases.ts:40</a></p><p>A raised surface — window/dialog interiors, menus, list bodies; sits above <a href="#background">background</a>.</p><hr><h3 id="backgroundselected" tabindex="-1">backgroundSelected <a class="header-anchor" href="#backgroundselected" aria-label="Permalink to &quot;backgroundSelected&quot;">​</a></h3><blockquote><p><code>readonly</code> <strong>backgroundSelected</strong>: <a href="./../type-aliases/Color.html"><code>Color</code></a></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/61db895436cf02931389daaaf2bf33e111871d25/packages/core/src/engine/color/aliases.ts#L44" target="_blank" rel="noreferrer">color/aliases.ts:44</a></p><p>A selected-but-unfocused row&#39;s fill — a quiet highlight distinct from the <a href="#accent">accent</a> focus fill.</p><hr><h3 id="backgroundsunken" tabindex="-1">backgroundSunken <a class="header-anchor" href="#backgroundsunken" aria-label="Permalink to &quot;backgroundSunken&quot;">​</a></h3><blockquote><p><code>readonly</code> <strong>backgroundSunken</strong>: <a href="./../type-aliases/Color.html"><code>Color</code></a></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/61db895436cf02931389daaaf2bf33e111871d25/packages/core/src/engine/color/aliases.ts#L42" target="_blank" rel="noreferrer">color/aliases.ts:42</a></p><p>A sunken surface — the well of an input/editor field, visually recessed below <a href="#backgroundraised">backgroundRaised</a>.</p><hr><h3 id="border" tabindex="-1">border <a class="header-anchor" href="#border" aria-label="Permalink to &quot;border&quot;">​</a></h3><blockquote><p><code>readonly</code> <strong>border</strong>: <a href="./../type-aliases/Color.html"><code>Color</code></a></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/61db895436cf02931389daaaf2bf33e111871d25/packages/core/src/engine/color/aliases.ts#L60" target="_blank" rel="noreferrer">color/aliases.ts:60</a></p><p>Frame and border lines on an active surface.</p><hr><h3 id="bordermuted" tabindex="-1">borderMuted <a class="header-anchor" href="#bordermuted" aria-label="Permalink to &quot;borderMuted&quot;">​</a></h3><blockquote><p><code>readonly</code> <strong>borderMuted</strong>: <a href="./../type-aliases/Color.html"><code>Color</code></a></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/61db895436cf02931389daaaf2bf33e111871d25/packages/core/src/engine/color/aliases.ts#L62" target="_blank" rel="noreferrer">color/aliases.ts:62</a></p><p>Dimmed border lines — an inactive window frame, an inter-column divider.</p><hr><h3 id="danger" tabindex="-1">danger <a class="header-anchor" href="#danger" aria-label="Permalink to &quot;danger&quot;">​</a></h3><blockquote><p><code>readonly</code> <strong>danger</strong>: <a href="./../type-aliases/Color.html"><code>Color</code></a></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/61db895436cf02931389daaaf2bf33e111871d25/packages/core/src/engine/color/aliases.ts#L66" target="_blank" rel="noreferrer">color/aliases.ts:66</a></p><p>Danger / destructive signal — error emphasis, a destructive action. Drives the <code>dangerText</code> UI role.</p><hr><h3 id="foreground" tabindex="-1">foreground <a class="header-anchor" href="#foreground" aria-label="Permalink to &quot;foreground&quot;">​</a></h3><blockquote><p><code>readonly</code> <strong>foreground</strong>: <a href="./../type-aliases/Color.html"><code>Color</code></a></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/61db895436cf02931389daaaf2bf33e111871d25/packages/core/src/engine/color/aliases.ts#L28" target="_blank" rel="noreferrer">color/aliases.ts:28</a></p><p>Primary body text — the default readable foreground on a normal surface.</p><hr><h3 id="foregrounddisabled" tabindex="-1">foregroundDisabled <a class="header-anchor" href="#foregrounddisabled" aria-label="Permalink to &quot;foregroundDisabled&quot;">​</a></h3><blockquote><p><code>readonly</code> <strong>foregroundDisabled</strong>: <a href="./../type-aliases/Color.html"><code>Color</code></a></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/61db895436cf02931389daaaf2bf33e111871d25/packages/core/src/engine/color/aliases.ts#L32" target="_blank" rel="noreferrer">color/aliases.ts:32</a></p><p>Disabled text — a greyed control&#39;s label; deliberately low-contrast.</p><hr><h3 id="foregroundmuted" tabindex="-1">foregroundMuted <a class="header-anchor" href="#foregroundmuted" aria-label="Permalink to &quot;foregroundMuted&quot;">​</a></h3><blockquote><p><code>readonly</code> <strong>foregroundMuted</strong>: <a href="./../type-aliases/Color.html"><code>Color</code></a></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/61db895436cf02931389daaaf2bf33e111871d25/packages/core/src/engine/color/aliases.ts#L30" target="_blank" rel="noreferrer">color/aliases.ts:30</a></p><p>De-emphasized text — captions, dividers, inactive titles; sits on the same surfaces as <a href="#foreground">foreground</a>.</p><hr><h3 id="foregroundonaccent" tabindex="-1">foregroundOnAccent <a class="header-anchor" href="#foregroundonaccent" aria-label="Permalink to &quot;foregroundOnAccent&quot;">​</a></h3><blockquote><p><code>readonly</code> <strong>foregroundOnAccent</strong>: <a href="./../type-aliases/Color.html"><code>Color</code></a></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/61db895436cf02931389daaaf2bf33e111871d25/packages/core/src/engine/color/aliases.ts#L34" target="_blank" rel="noreferrer">color/aliases.ts:34</a></p><p>Text drawn <em>on</em> the <a href="#accent">accent</a> fill — a button caption, a focused row; must contrast the accent.</p><hr><h3 id="info" tabindex="-1">info <a class="header-anchor" href="#info" aria-label="Permalink to &quot;info&quot;">​</a></h3><blockquote><p><code>readonly</code> <strong>info</strong>: <a href="./../type-aliases/Color.html"><code>Color</code></a></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/61db895436cf02931389daaaf2bf33e111871d25/packages/core/src/engine/color/aliases.ts#L72" target="_blank" rel="noreferrer">color/aliases.ts:72</a></p><p>Informational signal — a &quot;today&quot; marker, a neutral highlight.</p><hr><h3 id="menuaccelerator" tabindex="-1">menuAccelerator <a class="header-anchor" href="#menuaccelerator" aria-label="Permalink to &quot;menuAccelerator&quot;">​</a></h3><blockquote><p><code>readonly</code> <strong>menuAccelerator</strong>: <a href="./../type-aliases/Color.html"><code>Color</code></a></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/61db895436cf02931389daaaf2bf33e111871d25/packages/core/src/engine/color/aliases.ts#L56" target="_blank" rel="noreferrer">color/aliases.ts:56</a></p><p>The highlighted hotkey letter of the global chrome — the menu bar and the status line.</p><hr><h3 id="success" tabindex="-1">success <a class="header-anchor" href="#success" aria-label="Permalink to &quot;success&quot;">​</a></h3><blockquote><p><code>readonly</code> <strong>success</strong>: <a href="./../type-aliases/Color.html"><code>Color</code></a></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/61db895436cf02931389daaaf2bf33e111871d25/packages/core/src/engine/color/aliases.ts#L70" target="_blank" rel="noreferrer">color/aliases.ts:70</a></p><p>Success / positive signal — a completed action, a drag-in-progress indicator.</p><hr><h3 id="warning" tabindex="-1">warning <a class="header-anchor" href="#warning" aria-label="Permalink to &quot;warning&quot;">​</a></h3><blockquote><p><code>readonly</code> <strong>warning</strong>: <a href="./../type-aliases/Color.html"><code>Color</code></a></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/61db895436cf02931389daaaf2bf33e111871d25/packages/core/src/engine/color/aliases.ts#L68" target="_blank" rel="noreferrer">color/aliases.ts:68</a></p><p>Warning / attention signal. Drives the <code>warningText</code> UI role.</p>',96)])])}const u=a(s,[["render",n]]);export{f as __pageData,u as default};
